import React from 'react';
import LockIcon from '@mui/icons-material/Lock';
import PersonIcon from '@mui/icons-material/Person';
import EmailIcon from '@mui/icons-material/Email';
import BusinessIcon from '@mui/icons-material/Business';
import PeopleIcon from '@mui/icons-material/People';

const Topbar = ({ user, onLogout, activeTab }) => {
  if (!user) return null;

  const getDisplayName = (tab) => {
    switch (tab) {
      case 'she': return 'SHE Compliance';
      case 'risks': return 'Risk Registers';
      case 'assessment': return 'Risk Assessment';
      case 'controls': return 'Controls & Treatment';
      case 'montecarlo': return 'Monte Carlo Analysis';
      case 'bcm': return 'Business Continuity';
      case 'reports': return 'Analysis & Reports';
      case 'losses': return 'Loss Events';
      default: return tab.replace('-', ' ');
    }
  };

  return (
    <header className="topbar glass">
      <div className="topbar-left">
        <h1 style={{ fontSize: '20px', textTransform: 'capitalize', margin: 0 }}>
          {getDisplayName(activeTab)}
        </h1>
      </div>
      
      <div className="topbar-right">
        <div className="user-info-brief">
          <div className="user-details" style={{ marginRight: '15px' }}>
            <span className="user-name" style={{ fontWeight: 700, fontSize: '14px', color: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'flex-end', gap: '8px' }}>
              <PersonIcon style={{ fontSize: '18px' }} />
              {user.name || 'User Account'}
            </span>
            <span className="user-email" style={{ fontSize: '12px', opacity: 0.8, display: 'flex', alignItems: 'center', justifyContent: 'flex-end', gap: '8px', marginTop: '4px' }}>
              <EmailIcon style={{ fontSize: '14px' }} />
              {user.email}
            </span>
          </div>
        </div>
        
        <button className="btn-logout-top" onClick={onLogout} title="Logout">
          <LockIcon style={{ fontSize: '18px' }} />
          <span>Logout</span>
        </button>
      </div>
    </header>
  );
};

export default Topbar;
